// .commitlintrc.js
module.exports = {
  extends: ['@commitlint/config-conventional'],
  rules: {
    'type-enum': [2, 'always', [
      'prompt', 'tool', 'agent', 'eval',
      'fix', 'feat', 'chore', 'docs', 'ci',
    ]],
    // Enforce known scopes — update this list when new agents ship.
    'scope-enum': [2, 'always', [
      'triage-agent',
      'summariser',
      'classifier',
      'tool-schema',
      'eval-suite',
      'prompt-registry',
      'routing',
      '',            // empty scope allowed for cross-cutting chore/ci commits
    ]],
    'header-max-length': [2, 'always', 100],
    'subject-case': [2, 'always', 'lower-case'],
  },
};

# scripts/ci_routing.py
"""
Inspect the commit range for a PR and emit a JSON object
that describes which CI gates are required.

Usage:
    python scripts/ci_routing.py <base_sha> <head_sha>

Output (printed as JSON):
    {
      "run_eval_suite":      true,
      "run_schema_compat":   false,
      "run_breaking_review": true,
      "require_safety_team": true
    }
"""
import subprocess, json, re, sys

BREAKING_TYPES = {"prompt", "tool", "agent"}
EVAL_TYPES     = {"prompt", "tool", "agent", "eval", "fix"}
SCHEMA_TYPES   = {"tool"}

def get_commits(base: str, head: str) -> list[str]:
    """Return the list of commit subjects between base and head."""
    result = subprocess.run(
        ["git", "log", "--pretty=%s", f"{base}..{head}"],
        capture_output=True, text=True, check=True,
    )
    return result.stdout.strip().splitlines()

def parse_type(subject: str) -> tuple[str, bool]:
    """
    Parse the type token and breaking flag from a commit subject.

    Returns (type_token, is_breaking).
    Returns ('unknown', False) for non-conventional commits.
    """
    m = re.match(r"^([a-z]+)(?:\([^)]*\))?(!)?: ", subject)
    if not m:
        return "unknown", False
    return m.group(1), m.group(2) == "!"

def compute_required_gates(base: str, head: str) -> dict:
    """
    Walk the commit range and compute the union of required CI gates.
    """
    commits = get_commits(base, head)
    gates = {
        "run_eval_suite":      False,
        "run_schema_compat":   False,
        "run_breaking_review": False,
        "require_safety_team": False,
    }
    for subject in commits:
        ctype, is_breaking = parse_type(subject)
        if ctype in EVAL_TYPES:
            gates["run_eval_suite"] = True
        if ctype in SCHEMA_TYPES:
            gates["run_schema_compat"] = True
        if is_breaking and ctype in BREAKING_TYPES:
            gates["run_breaking_review"] = True
            gates["require_safety_team"] = True
    return gates

if __name__ == "__main__":
    base_sha, head_sha = sys.argv[1], sys.argv[2]
    print(json.dumps(compute_required_gates(base_sha, head_sha), indent=2))

# .releaserc.json — semantic-release configuration
{
  "branches": ["main"],
  "plugins": [
    "@semantic-release/commit-analyzer",
    ["@semantic-release/release-notes-generator", {
      "preset": "conventionalcommits",
      "presetConfig": {
        "types": [
          { "type": "prompt",  "section": "Prompt Changes" },
          { "type": "tool",    "section": "Tool Schema Changes" },
          { "type": "agent",   "section": "Agent Logic Changes" },
          { "type": "eval",    "section": "Evaluation Suite" },
          { "type": "fix",     "section": "Bug Fixes" },
          { "type": "feat",    "section": "New Features" },
          { "type": "chore",   "hidden": true },
          { "type": "docs",    "hidden": true }
        ]
      }
    }],
    "@semantic-release/changelog",
    "@semantic-release/git"
  ]
}
